import express from "express";
import crypto from "crypto";
import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";
import { getSignedUrl } from "@aws-sdk/s3-request-presigner";

const s3 = new S3Client({ region: "us-east-1" });
const BUCKET = "acme-uploads";
const MAX_BYTES = 5 * 1024 * 1024;

const app = express();
app.use(express.json());

// authMiddleware sets req.user.id from a verified token
app.post("/uploads/avatar", authMiddleware, async (req, res) => {
  const { contentLength } = req.body as { contentLength: number };

  if (!Number.isInteger(contentLength) || contentLength <= 0 || contentLength > MAX_BYTES) {
    return res.status(400).json({ error: "invalid or oversized file" });
  }

  const fileId = crypto.randomUUID();
  const key = `avatars/${req.user.id}/${fileId}.jpg`;

  const cmd = new PutObjectCommand({
    Bucket: BUCKET,
    Key: key,
    ContentType: "image/jpeg",      // signature binds the type
    ContentLength: contentLength,    // signature binds the exact size
    ServerSideEncryption: "aws:kms",
    SSEKMSKeyId: process.env.AVATAR_KMS_KEY_ARN,
  });

  // URL valid for 120s, usable only for this exact key/type/size
  const url = await getSignedUrl(s3, cmd, { expiresIn: 120 });
  return res.json({ uploadUrl: url, key });
});

// Client then does: PUT uploadUrl with headers
//   Content-Type: image/jpeg
//   Content-Length: <contentLength>
// Any mismatch => 403 SignatureDoesNotMatch from S3.

function authMiddleware(req: any, res: any, next: any) {
  // verify token, set req.user; omitted for brevity
  next();
}

app.listen(3000);
